    int fd = open("/kf_thread_no_such_file", O_RDONLY);
    if (fd == ____) {
        printf("Thread A: errno=%d (%s)\n", errno, strerror(errno));
    }
    return NULL;
}

void *thread_eacces(void *arg) {
    (void)arg;
    int fd = open("/tmp/kf_thread_ro.txt", O_CREAT | O_WRONLY, 0444);
    if (fd >= 0) { close(fd); }
    fd = open("/tmp/kf_thread_ro.txt", ____);
    if (fd == -1) {
        printf("Thread B: errno=%d (%s)\n", errno, strerror(errno));
    } else { close(fd); }
    unlink("/tmp/kf_thread_ro.txt");
    return NULL;
}

int main(void) {
    pthread_t ta, tb;
    pthread_create(&ta, NULL, thread_enoent, NULL);
    pthread_join(ta, NULL);
    pthread_create(&tb, NULL, thread_eacces, NULL);
    pthread_join(tb, NULL);
    printf("errno is thread-local: yes\n");
    return 0;
}

